#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct McpMethodSpec {
    pub id: &'static str,
    pub rpc: &'static str,
    pub tool: Option<&'static str>,
    pub description: &'static str,
}

pub const MCP_METHODS: &[McpMethodSpec] = &[
    McpMethodSpec {
        id: "initialize",
        rpc: "initialize",
        tool: None,
        description: "Open an MCP session and fetch server capabilities and instructions.",
    },
    McpMethodSpec {
        id: "ping",
        rpc: "ping",
        tool: None,
        description: "Check gateway liveness over JSON-RPC.",
    },
    McpMethodSpec {
        id: "list_tools",
        rpc: "tools/list",
        tool: None,
        description: "List the fixed ten-verb Tempera capability-fabric surface; product cards never appear as flat product tool names.",
    },
    McpMethodSpec {
        id: "call_tool",
        rpc: "tools/call",
        tool: None,
        description: "Call a fixed fabric verb. Discover product cards with tempera_search, inspect a card with tempera_describe, then invoke its opaque capability reference through tempera_invoke or tempera_prepare/tempera_commit.",
    },
    McpMethodSpec {
        id: "whoami",
        rpc: "tools/call",
        tool: Some("tempera_whoami"),
        description: "Fetch the caller's identity, workspace, and scopes as seen by the gateway.",
    },
    McpMethodSpec {
        id: "status",
        rpc: "tools/call",
        tool: Some("tempera_status"),
        description: "Fetch gateway upstream health for every connected product MCP server.",
    },
];

pub const MCP_ERROR_PLAN_LIMIT: i64 = -32002;
pub const MCP_ERROR_INVALID_REQUEST: i64 = -32600;
pub const MCP_ERROR_METHOD_NOT_FOUND: i64 = -32601;
pub const MCP_ERROR_INVALID_PARAMS: i64 = -32602;
pub const MCP_ERROR_INTERNAL: i64 = -32603;

/// Look up one operation by product key and snake_case operation id.
pub fn find_operation(product: &str, id: &str) -> Option<&'static OperationSpec> {
    OPERATIONS
        .iter()
        .find(|op| op.product == product && op.id == id)
}

/// Look up one product by snake_case key.
pub fn find_product(key: &str) -> Option<&'static ProductSpec> {
    PRODUCTS.iter().find(|product| product.key == key)
}
